#include <ModelBuilder/MultiModelBuilder.hpp>

#include <DataTable/DataTable.h>

#include <filesystem>
#include <iostream>
#include <sstream>
#include <string_view>
#include <vector>

int main(int argc, char** argv) {
  // This example demonstrates the multi-tree artifact:
  //  - build many target-column trees in parallel
  //  - write mb_trees.bin + mb_map.bin
  //  - serialize/deserialize the MultiModelBuilder object itself
  //  - getTree(targetColumn) to lazily fetch one TreeBuilder

  const std::filesystem::path csvPath = std::filesystem::path{"examples"} / "sample_data" / "ptsd.csv";
  const std::filesystem::path parsedDir = std::filesystem::path{"build"} / "datasets" / "ptsd_output";
  const std::filesystem::path modelOutDir = std::filesystem::path{"build"} / "models" / "ptsd_model";

  const bool forceReparse = (argc > 1 && std::string_view(argv[1]) == "--reparse");

  try {
    // Parse once using DataTable.
    DataTableLib::DataTable dt;
    const auto metaDir = parsedDir / "meta_data";
    if (!forceReparse && std::filesystem::exists(metaDir)) {
      dt.load(parsedDir.string());
      std::cout << "Loaded parsed dataset: " << parsedDir << "\n";
    } else {
      dt.setInputFilePath(csvPath.string());
      dt.setOutputDirectory(parsedDir.string());
      dt.parse(/*threads=*/1);
      std::cout << "Parsed CSV: " << csvPath << " -> " << parsedDir << "\n";
    }

    const std::size_t cols = static_cast<std::size_t>(dt.getColumnCount());
    if (cols < 3) {
      throw std::runtime_error("Need at least 3 columns for this example (id + >=2 features)");
    }

    // Parameters.
    const std::size_t maxDepth = 0; // unlimited
    const double columnAlpha = 0.05;
    const bool columnAlphaBonferroni = true;
    const double partitionAlpha = 0.05;
    const bool partitionAlphaBonferroni = false;

    // analysisColumns: all columns except column 0 (id).
    std::vector<std::size_t> analysisColumns;
    analysisColumns.reserve(cols);
    for (std::size_t c = 0; c < cols; ++c) {
      if (c == 0) continue;
      analysisColumns.push_back(c);
    }

    // targetColumns: all columns except column 0 (id).
    // NOTE: per-tree build will remove the target column from analysis columns.
    std::vector<std::size_t> targetColumns = analysisColumns;

    const std::size_t threadCount = 4;

    // Build and write out the multi-tree artifact.
    auto multi = modelbuilder::MultiModelBuilder::buildAndWrite(parsedDir.string(),
                                                                modelOutDir.string(),
                                                                targetColumns,
                                                                maxDepth,
                                                                columnAlpha,
                                                                columnAlphaBonferroni,
                                                                partitionAlpha,
                                                                partitionAlphaBonferroni,
                                                                analysisColumns,
                                                                threadCount);

    std::cout << "Built " << multi.treeCount() << " trees into: " << modelOutDir << "\n";
    std::cout << "  - mb_trees.bin\n";
    std::cout << "  - mb_map.bin\n";

    // Serialize/deserialize the MultiModelBuilder object itself (metadata + cached map).
    std::stringstream ss(std::ios::in | std::ios::out | std::ios::binary);
    multi.serialize(ss);
    ss.seekg(0);
    auto multi2 = modelbuilder::MultiModelBuilder::deserialize(ss);

    // Ensure lazy map is available even if we "forgot" it.
    // (deserialize() already loads an embedded copy, but loadMap() will rebuild from disk.)
    multi2.loadMap();

    // Fetch one TreeBuilder for a specific target.
    const std::uint64_t wantTarget = 1;
    auto treeArtifact = multi2.getTree(wantTarget);

    std::cout << "Fetched tree for targetColumn=" << wantTarget
              << " with elements=" << treeArtifact.tree().elementCount() << "\n";

  } catch (const std::exception& e) {
    std::cout << "ModelBuilder_example failed: " << e.what() << "\n";
    return 1;
  }

  return 0;
}

#include <ModelBuilder/ModelBuilder.hpp>
#include <ModelBuilder/TreeBuilder.hpp>

#include <DataTable/DataTable.h>

#include <filesystem>
#include <iostream>

int main(int argc, char** argv) {
  // ModelBuilder remains available as an interactive builder / utilities host.
  // TreeBuilder is the serializable single-tree artifact.
  modelbuilder::ModelBuilder mb;

  // Input CSV (categorical data expected).
  const std::filesystem::path csvPath = std::filesystem::path{"examples"} / "sample_data" / "ptsd.csv";

  // DataTable parses CSVs into an output directory layout (meta_data/ + mapped_data/).
  // That parsed directory is what FeatureSelector/ModelBuilder expects to load.
  const std::filesystem::path parsedDir = std::filesystem::path{"build"} / "datasets" / "ptsd_output";

  const bool forceReparse = (argc > 1 && std::string_view(argv[1]) == "--reparse");

  try {
    DataTableLib::DataTable dt;
    const auto metaDir = parsedDir / "meta_data";
    if (!forceReparse && std::filesystem::exists(metaDir)) {
      // Fast path: reuse previous parse output.
      dt.load(parsedDir.string());
      std::cout << "Loaded parsed dataset: " << parsedDir << "\n";
    } else {
      // Parse CSV -> output directory (safe to re-run; it will overwrite/update outputs).
      dt.setInputFilePath(csvPath.string());
      dt.setOutputDirectory(parsedDir.string());
      dt.parse(/*threads=*/1);
      std::cout << "Parsed CSV: " << csvPath << " -> " << parsedDir << "\n";
    }
    std::cout << "Columns: " << dt.getColumnCount() << ", Rows (incl header): " << dt.getRowCount() << "\n";
    if (dt.getColumnCount() > 0) {
      std::cout << "First column header: " << dt.getColumnHeader(0) << "\n";
    }

    // Configure build parameters.
    // Column 0 is an identifier (record_id) and must be excluded from both target and split candidates.
    const std::size_t targetColumn = 1;
    const std::size_t maxDepth = 0; // 0 => unlimited

    // Significance thresholds.
    const double columnAlpha = 0.05;
    const bool columnAlphaBonferroni = true;
    const double partitionAlpha = 0.05;
    const bool partitionAlphaBonferroni = false;

    // Optional: restrict split candidate columns for building/training.
    // These analysis columns are NOT stored in the resulting TreeBuilder artifact serialization.
    // For a simple example, enable all columns except id and target.
    std::vector<std::size_t> analysisColumns;
    analysisColumns.reserve(static_cast<std::size_t>(dt.getColumnCount()));
    for (std::size_t c = 0; c < static_cast<std::size_t>(dt.getColumnCount()); ++c) {
      if (c == 0) continue; // exclude id column
      if (c == targetColumn) continue; // exclude target column
      analysisColumns.push_back(c);
    }

    // Build the serializable artifact.
    auto artifact = modelbuilder::TreeBuilder::buildFromDataDir(parsedDir.string(),
                                                                targetColumn,
                                                                maxDepth,
                                                                columnAlpha,
                                                                columnAlphaBonferroni,
                                                                partitionAlpha,
                                                                partitionAlphaBonferroni,
                                                                analysisColumns);

    const auto& tree = artifact.tree();
    std::cout << "Built tree with " << tree.elementCount() << " elements\n";
    mb.createGraphviz(tree, "modelbuilder_tree.dot");
    std::cout << "Wrote modelbuilder_tree.dot (render with: dot -Tpng modelbuilder_tree.dot -o tree.png)\n";
  } catch (const std::exception& e) {
    std::cout << "ModelBuilder example failed: " << e.what() << "\n";
    return 1;
  }
  return 0;
}

#pragma once

#include <cpp_type_concepts/Serializable.hpp>

#include <cstdint>
#include <istream>
#include <ostream>
#include <stdexcept>

namespace modelbuilder {

// Trivial leaf payload placeholder. Will be extended later.
// Serialization format (big-endian, no versioning): u32 placeholder.
class LeafData {
public:
  LeafData() = default;
  explicit LeafData(std::uint32_t placeholder) : placeholder_(placeholder) {}

  [[nodiscard]] std::uint32_t placeholder() const noexcept { return placeholder_; }

  void serialize(std::ostream& out) const {
    out.put(static_cast<char>((placeholder_ >> 24) & 0xFFu));
    out.put(static_cast<char>((placeholder_ >> 16) & 0xFFu));
    out.put(static_cast<char>((placeholder_ >> 8) & 0xFFu));
    out.put(static_cast<char>(placeholder_ & 0xFFu));
    if (!out) throw std::runtime_error("LeafData::serialize failed");
  }

  static LeafData deserialize(std::istream& in) {
    std::uint32_t v = 0;
    for (int i = 0; i < 4; ++i) {
      const int c = in.get();
      if (c == std::char_traits<char>::eof()) throw std::runtime_error("LeafData::deserialize failed");
      v = (v << 8) | static_cast<std::uint32_t>(static_cast<unsigned char>(c));
    }
    return LeafData{v};
  }

private:
  std::uint32_t placeholder_ = 0;
};

static_assert(cpp_type_concepts::Serializable<LeafData>);

} // namespace modelbuilder

#pragma once

#include <cpp_type_concepts/Serializable.hpp>

#include <cstdint>
#include <map>
#include <istream>
#include <ostream>
#include <stdexcept>

namespace modelbuilder {

// Leaf payload.
//
// A leaf can happen for two reasons:
//  - NoSignificantColumn: FeatureSelector did not find any significant split candidate.
//  - NoSignificantPartition: A significant column was found but no significant partition.
//
// If a significant column was found, splitColumnIndex is that column index. Otherwise it is -1.
//
// Serialization format (big-endian, no versioning):
//   u8  reason
//   i64 splitColumnIndexOrMinusOne
//   u64 targetCounts.size
//   repeat targetCounts.size times:
//      u32 targetValue
//      u64 count
class LeafData {
public:
  enum class Reason : std::uint8_t {
    NoSignificantColumn = 0,
    NoSignificantPartition = 1,
  };

  LeafData() = default;

  LeafData(Reason reason,
           std::int64_t splitColumnIndexOrMinusOne,
           std::map<std::uint32_t, std::uint64_t> targetCounts)
      : reason_(reason),
        splitColumnIndexOrMinusOne_(splitColumnIndexOrMinusOne),
        targetCounts_(std::move(targetCounts)) {}

  static LeafData noSignificantColumn(std::map<std::uint32_t, std::uint64_t> targetCounts) {
    return LeafData{Reason::NoSignificantColumn, -1, std::move(targetCounts)};
  }
  static LeafData noSignificantPartition(std::size_t significantColumnIndex,
                                        std::map<std::uint32_t, std::uint64_t> targetCounts) {
    return LeafData{Reason::NoSignificantPartition,
                    static_cast<std::int64_t>(significantColumnIndex),
                    std::move(targetCounts)};
  }

  [[nodiscard]] Reason reason() const noexcept { return reason_; }
  [[nodiscard]] std::int64_t splitColumnIndexOrMinusOne() const noexcept { return splitColumnIndexOrMinusOne_; }
  [[nodiscard]] const std::map<std::uint32_t, std::uint64_t>& targetCounts() const noexcept { return targetCounts_; }

  void serialize(std::ostream& out) const {
    out.put(static_cast<char>(static_cast<std::uint8_t>(reason_)));

    const auto u = static_cast<std::uint64_t>(splitColumnIndexOrMinusOne_);
    out.put(static_cast<char>((u >> 56) & 0xFFu));
    out.put(static_cast<char>((u >> 48) & 0xFFu));
    out.put(static_cast<char>((u >> 40) & 0xFFu));
    out.put(static_cast<char>((u >> 32) & 0xFFu));
    out.put(static_cast<char>((u >> 24) & 0xFFu));
    out.put(static_cast<char>((u >> 16) & 0xFFu));
    out.put(static_cast<char>((u >> 8) & 0xFFu));
    out.put(static_cast<char>(u & 0xFFu));

    const auto n = static_cast<std::uint64_t>(targetCounts_.size());
    out.put(static_cast<char>((n >> 56) & 0xFFu));
    out.put(static_cast<char>((n >> 48) & 0xFFu));
    out.put(static_cast<char>((n >> 40) & 0xFFu));
    out.put(static_cast<char>((n >> 32) & 0xFFu));
    out.put(static_cast<char>((n >> 24) & 0xFFu));
    out.put(static_cast<char>((n >> 16) & 0xFFu));
    out.put(static_cast<char>((n >> 8) & 0xFFu));
    out.put(static_cast<char>(n & 0xFFu));

    for (const auto& [k, v] : targetCounts_) {
      out.put(static_cast<char>((k >> 24) & 0xFFu));
      out.put(static_cast<char>((k >> 16) & 0xFFu));
      out.put(static_cast<char>((k >> 8) & 0xFFu));
      out.put(static_cast<char>(k & 0xFFu));

      out.put(static_cast<char>((v >> 56) & 0xFFu));
      out.put(static_cast<char>((v >> 48) & 0xFFu));
      out.put(static_cast<char>((v >> 40) & 0xFFu));
      out.put(static_cast<char>((v >> 32) & 0xFFu));
      out.put(static_cast<char>((v >> 24) & 0xFFu));
      out.put(static_cast<char>((v >> 16) & 0xFFu));
      out.put(static_cast<char>((v >> 8) & 0xFFu));
      out.put(static_cast<char>(v & 0xFFu));
    }
    if (!out) throw std::runtime_error("LeafData::serialize failed");
  }

  static LeafData deserialize(std::istream& in) {
    const int rc = in.get();
    if (rc == std::char_traits<char>::eof()) throw std::runtime_error("LeafData::deserialize failed");
    const auto reason = static_cast<Reason>(static_cast<std::uint8_t>(static_cast<unsigned char>(rc)));

    std::uint64_t u = 0;
    for (int i = 0; i < 8; ++i) {
      const int c = in.get();
      if (c == std::char_traits<char>::eof()) throw std::runtime_error("LeafData::deserialize failed");
      u = (u << 8) | static_cast<std::uint64_t>(static_cast<unsigned char>(c));
    }
    const auto idx = static_cast<std::int64_t>(u);

    std::uint64_t n = 0;
    for (int i = 0; i < 8; ++i) {
      const int c = in.get();
      if (c == std::char_traits<char>::eof()) throw std::runtime_error("LeafData::deserialize failed");
      n = (n << 8) | static_cast<std::uint64_t>(static_cast<unsigned char>(c));
    }

    std::map<std::uint32_t, std::uint64_t> counts;
    for (std::uint64_t i = 0; i < n; ++i) {
      std::uint32_t k = 0;
      for (int j = 0; j < 4; ++j) {
        const int c = in.get();
        if (c == std::char_traits<char>::eof()) throw std::runtime_error("LeafData::deserialize failed");
        k = (k << 8) | static_cast<std::uint32_t>(static_cast<unsigned char>(c));
      }

      std::uint64_t v = 0;
      for (int j = 0; j < 8; ++j) {
        const int c = in.get();
        if (c == std::char_traits<char>::eof()) throw std::runtime_error("LeafData::deserialize failed");
        v = (v << 8) | static_cast<std::uint64_t>(static_cast<unsigned char>(c));
      }
      counts.emplace(k, v);
    }

    return LeafData{reason, idx, std::move(counts)};
  }

private:
  Reason reason_ = Reason::NoSignificantColumn;
  std::int64_t splitColumnIndexOrMinusOne_ = -1;
  std::map<std::uint32_t, std::uint64_t> targetCounts_;
};

static_assert(cpp_type_concepts::Serializable<LeafData>);

} // namespace modelbuilder

#pragma once

#include <ModelBuilder/TreeBuilder.hpp>

#include <cpp_type_concepts/Serializable.hpp>

#include <cstddef>
#include <cstdint>
#include <iosfwd>
#include <string>
#include <unordered_map>
#include <utility>
#include <vector>

namespace modelbuilder {

// MultiModelBuilder: builds and stores many TreeBuilder artifacts.
//
// On-disk layout (big-endian, no versioning):
//   mb_trees.bin: repeated records
//       u64 treeLen
//       u8[treeLen] treeBytes (TreeBuilder::serialize output)
//   mb_map.bin: length+bytes wrapper
//       u64 payloadLen
//       payload = repeated pairs:
//           u64 targetColumn
//           u64 fileOffset   (byte offset into mb_trees.bin where the record's treeLen starts)
//
// The MultiModelBuilder object itself is Serializable and captures enough metadata to reopen the
// two files later and support lazy getTree(targetColumn).
class MultiModelBuilder {
public:
  MultiModelBuilder() = default;

  // Build all trees for the given target columns and write mb_trees.bin + mb_map.bin into outputDir.
  static MultiModelBuilder buildAndWrite(const std::string& parsedDir,
                                         const std::string& outputDir,
                                         const std::vector<std::size_t>& targetColumns,
                                         std::size_t maxDepth,
                                         double columnAlpha,
                                         bool columnAlphaApplyBonferroni,
                                         double partitionAlpha,
                                         bool partitionAlphaApplyBonferroni,
                                         const std::vector<std::size_t>& analysisColumns,
                                         std::size_t threadCount);

  [[nodiscard]] const std::string& parsedDir() const noexcept { return parsedDir_; }
  [[nodiscard]] const std::string& outputDir() const noexcept { return outputDir_; }

  [[nodiscard]] std::size_t maxDepth() const noexcept { return maxDepth_; }
  [[nodiscard]] double columnAlpha() const noexcept { return columnAlpha_; }
  [[nodiscard]] bool columnAlphaApplyBonferroni() const noexcept { return columnAlphaApplyBonferroni_; }
  [[nodiscard]] double partitionAlpha() const noexcept { return partitionAlpha_; }
  [[nodiscard]] bool partitionAlphaApplyBonferroni() const noexcept { return partitionAlphaApplyBonferroni_; }

  // Lazy-load a tree for the provided target column.
  [[nodiscard]] TreeBuilder getTree(std::uint64_t targetColumn) const;

  void serialize(std::ostream& out) const;
  static MultiModelBuilder deserialize(std::istream& in);

  // (Re)load mb_map.bin into memory. Called automatically by deserialize().
  void loadMap();

  [[nodiscard]] std::size_t treeCount() const noexcept { return targetToOffset_.size(); }

private:
  static std::string treesPath_(const std::string& outputDir);
  static std::string mapPath_(const std::string& outputDir);

  static void writeU8_(std::ostream& out, std::uint8_t v);
  static std::uint8_t readU8_(std::istream& in);
  static void writeU64BE_(std::ostream& out, std::uint64_t v);
  static std::uint64_t readU64BE_(std::istream& in);
  static void writeF64BE_(std::ostream& out, double d);
  static double readF64BE_(std::istream& in);
  static void writeBool_(std::ostream& out, bool b);
  static bool readBool_(std::istream& in);
  static void writeString_(std::ostream& out, const std::string& s);
  static std::string readString_(std::istream& in);

  std::string parsedDir_;
  std::string outputDir_;

  std::size_t maxDepth_ = 0;
  double columnAlpha_ = 0.05;
  bool columnAlphaApplyBonferroni_ = true;
  double partitionAlpha_ = 0.05;
  bool partitionAlphaApplyBonferroni_ = false;

  // targetColumn -> file offset in mb_trees.bin
  std::unordered_map<std::uint64_t, std::uint64_t> targetToOffset_;
};

static_assert(cpp_type_concepts::Serializable<MultiModelBuilder>);

} // namespace modelbuilder

#include <ModelBuilder/ModelBuilder.hpp>

#include <ContingencyTable/FeatureSelector.h>

#include <algorithm>
#include <cctype>
#include <fstream>
#include <iomanip>
#include <limits>
#include <memory>
#include <sstream>
#include <stdexcept>

namespace modelbuilder {

struct ModelBuilder::Impl {
  ContingencyTableLib::FeatureSelector selector;

  std::string dataPath;
  bool loaded = false;

  std::size_t targetColumn = 0;

  // Row marker vector used by FeatureSelector::enabledRows(vector<uint32_t>&,...)
  std::vector<std::uint32_t> rowIndices;

  // Enabled columns bitmask for FeatureSelector::enabledColumns
  std::vector<std::uint32_t> enabledColumnsBitmask;
  bool hasAnalysisColumns = false;

  void ensureLoaded() const {
    if (!loaded) throw std::logic_error("ModelBuilder: call loadDataDir() before building");
  }

  static std::vector<std::uint32_t> makeBitmaskFromIndices(std::size_t numBits,
                                                          const std::vector<std::size_t>& indices) {
    const std::size_t numWords = (numBits + 31) / 32;
    std::vector<std::uint32_t> bm(numWords, 0);
    for (std::size_t idx : indices) {
      if (idx >= numBits) {
        throw std::out_of_range("ModelBuilder: column index out of range");
      }
      bm[idx / 32] |= (1u << (idx % 32));
    }
    return bm;
  }
};

ModelBuilder::ModelBuilder() : impl_(new Impl()) {}
ModelBuilder::~ModelBuilder() { delete impl_; }
ModelBuilder::ModelBuilder(ModelBuilder&& other) noexcept : impl_(other.impl_) { other.impl_ = nullptr; }
ModelBuilder& ModelBuilder::operator=(ModelBuilder&& other) noexcept {
  if (this == &other) return *this;
  delete impl_;
  impl_ = other.impl_;
  other.impl_ = nullptr;
  return *this;
}

void ModelBuilder::loadDataDir(const std::string& path) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->dataPath = path;
  impl_->selector.load(path);
  impl_->loaded = true;

  const auto rows = impl_->selector.getRowCount();
  if (rows > static_cast<std::uint64_t>(std::numeric_limits<std::size_t>::max())) {
    throw std::overflow_error("ModelBuilder: row count too large for internal buffers");
  }
  impl_->rowIndices.assign(static_cast<std::size_t>(rows), 0);
  if (!impl_->rowIndices.empty()) {
    // DataTable underlying ContingencyTable uses row 0 as header row.
    // Keep it permanently disabled in the marker scheme.
    impl_->rowIndices[0] = std::numeric_limits<std::uint32_t>::max();
  }
}

void ModelBuilder::setTargetColumn(std::size_t columnIndex) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->targetColumn = columnIndex;
  if (impl_->loaded) {
    if (columnIndex >= impl_->selector.getColumnCount()) {
      throw std::out_of_range("ModelBuilder: target column out of range");
    }
    impl_->selector.setTargetColumn(columnIndex);
  }
}

void ModelBuilder::setColumnAlpha(double alpha, bool applyBonferroni) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();
  impl_->selector.setColumnAlpha(alpha, applyBonferroni);
}

void ModelBuilder::setPartitionAlpha(double alpha, bool applyBonferroni) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();
  impl_->selector.setPartitionAlpha(alpha, applyBonferroni);
}

void ModelBuilder::setAnalysisColumns(const std::vector<std::size_t>& columnIndices) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();

  const auto cols = impl_->selector.getColumnCount();
  if (cols > static_cast<std::uint64_t>(std::numeric_limits<std::size_t>::max())) {
    throw std::overflow_error("ModelBuilder: column count too large for internal buffers");
  }
  impl_->enabledColumnsBitmask = Impl::makeBitmaskFromIndices(static_cast<std::size_t>(cols), columnIndices);
  impl_->hasAnalysisColumns = true;

  impl_->selector.enabledColumns(impl_->enabledColumnsBitmask.data(), static_cast<std::size_t>(cols));
}

ModelBuilder::Tree ModelBuilder::buildTree(std::size_t maxDepth) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();

  if (impl_->targetColumn >= impl_->selector.getColumnCount()) {
    throw std::out_of_range("ModelBuilder: target column out of range");
  }
  impl_->selector.setTargetColumn(impl_->targetColumn);

  // If analysis columns not set, default to "all columns" and let FeatureSelector do its own exclusions
  // (typically it excludes target column internally).
  if (impl_->hasAnalysisColumns) {
    const auto cols = impl_->selector.getColumnCount();
    impl_->selector.enabledColumns(impl_->enabledColumnsBitmask.data(), static_cast<std::size_t>(cols));
  }

  Tree tree;

  auto countEnabledRowsAfterApplyingPartition = [&](std::uint32_t threshold,
                                                    std::size_t splitColumnIndex,
                                                    const std::vector<std::uint32_t>& allowedValues) -> std::uint64_t {
    // Take a copy so we can apply an additional filter without mutating the live marker state.
    auto tmp = impl_->rowIndices;
    impl_->selector.enabledRows(tmp, threshold, allowedValues, splitColumnIndex);
    std::uint64_t c = 0;
    for (std::size_t i = 1; i < tmp.size(); ++i) {
      if (tmp[i] == 0) ++c;
    }
    return c;
  };

  auto rebuildEnabledRowsForCurrentPosition = [&]() {
    // Recompute selector row state for the current insertion point by applying
    // the sequence of splits from the root down to the *parent* of the next element.
    // This avoids subtle inconsistencies when LeftTree backtracks from a fully-grown
    // left branch to a right branch.
    const auto* cur = tree.getCurrentNode();
    if (!cur) return;

    // Restore row marker state to what it looked like when we *arrived* at the current node.
    // Contract (as used by FeatureSelector::enabledRows(rowIndices,...)):
    // - When a node with id=N applies a partition filter, any row excluded is marked with value N.
    // - When backtracking to (or re-evaluating under) node N, we must re-enable all rows that were
    //   excluded by node N or any deeper node, i.e. clear markers >= N back to 0.
    const auto curIdU32 = static_cast<std::uint32_t>(cur->id);
    for (auto& m : impl_->rowIndices) {
      if (m >= curIdU32) m = 0;
    }

    // Keep DataTable header row permanently disabled in our marker scheme.
    if (!impl_->rowIndices.empty()) {
      impl_->rowIndices[0] = std::numeric_limits<std::uint32_t>::max();
    }

    // Collect the path nodes from root to current.
    std::vector<const Tree::Node*> path;
    for (const Tree::Node* n = cur; n != nullptr; ) {
      path.push_back(n);

      // Find parent by scanning ids downwards (IDs are sequential and parent is < child).
      const Tree::Node* parent = nullptr;
      for (Tree::Id pid = n->id - 1; pid >= 0; --pid) {
        const auto* cand = tree.getNode(pid);
        if (!cand) continue;
        // Use pointer identity (not just id) to avoid mismatches during construction.
        if ((cand->left && cand->left.get() == n) || (cand->right && cand->right.get() == n)) {
          parent = cand;
          break;
        }
      }
      n = parent;
    }
    std::reverse(path.begin(), path.end());

    // Apply each ancestor split on the way down, but only for ancestors of the current insertion node.
    // The current insertion node's own split has NOT been taken yet (we are about to decide
    // its left vs right child), so applying it here would incorrectly filter out rows.
    if (path.size() <= 1) return;
    for (std::size_t i = 0; i + 1 < path.size(); ++i) {
      const auto* n = path[i];
      if (!n->data.has_value()) continue;
      const auto& nd = *n->data;

      // Determine which branch we took from this node.
      const auto* child = path[i + 1];
      const bool tookLeft = (n->left && n->left.get() == child);

      // IMPORTANT: By contract, FeatureSelector partition "one" corresponds to the left branch
      // (LeftTree edge label "L") and partition "two" corresponds to the right branch.
      // NodeData stores these as leftPartitionValues/rightPartitionValues.
      const auto& allowed = tookLeft ? nd.leftPartitionValues() : nd.rightPartitionValues();

      // Use threshold == node id.
      // This means: before applying this node's whitelist, re-enable any rows that were previously
      // disabled at this node or deeper (marker >= nodeId).
      impl_->selector.enabledRows(impl_->rowIndices,
                                 static_cast<std::uint32_t>(n->id),
                                 allowed,
                                 static_cast<std::size_t>(nd.splitColumnIndex()));
    }

    // Finally, apply the *current node's* branch filter for the next insertion (left child first,
    // and after backtracking, right child). This is the critical step that makes the enabled rows
    // for the soon-to-be-created child match the parent's left/right partition counts.
    if (auto* insertionParent = tree.getCurrentNode(); insertionParent && insertionParent->data.has_value()) {
      const auto& nd = *insertionParent->data;
      const bool insertingLeft = (insertionParent->left == nullptr);
      const auto& allowed = insertingLeft ? nd.leftPartitionValues() : nd.rightPartitionValues();
      impl_->selector.enabledRows(impl_->rowIndices,
                                 static_cast<std::uint32_t>(insertionParent->id),
                                 allowed,
                                 static_cast<std::size_t>(nd.splitColumnIndex()));
    }
  };

  // LeftTree considers an empty tree "complete" (current node == nullptr). Seed a root element.
  // The root decision is based on feature selection on all currently enabled rows.
  impl_->selector.findSignificantColumn();
  if (!impl_->selector.significantColumnFound() || !impl_->selector.significantPartitionFound()) {
    tree.createLeaf(LeafData{0});
  } else {
    const auto nodeIdForCounts = static_cast<std::uint32_t>(tree.currentNodeID() < 0 ? 0 : tree.currentNodeID());
    const auto splitColumnIndex = static_cast<std::uint64_t>(impl_->selector.getSignificantColumnIndex());
    // Partition "one" is left, partition "two" is right.
    auto leftValues = impl_->selector.getFirstPartition();
    auto rightValues = impl_->selector.getSecondPartition();

    // Counts are defined as the number of rows reaching each branch (child) of this node.
    // Compute using the current enabled set (rows reaching this node) and applying the node's
    // own partition whitelist to a temporary marker vector.
    // When applying a hypothetical partition filter for counting purposes, we must not clear
    // any markers that represent the current node's arrival state. Since enabledRows() clears
    // markers >= threshold, use (nodeId + 1) here.
    const auto countThreshold = nodeIdForCounts + 1;
    const auto leftCount = countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), leftValues);
    const auto rightCount = countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), rightValues);

    tree.createNode(modelbuilder::NodeData{splitColumnIndex, std::move(leftValues), std::move(rightValues), leftCount, rightCount});
  }

  // Depth tracking aligned to insertion path. LeftTree stores its own path privately, so we track here.
  // We push depth when we create a node (descend), and pop when LeftTree backtracks after leaf insertion.
  // To detect backtracking we can observe currentNodeID changes, but simplest is to recompute via tree.getCurrentNode().
  std::vector<Tree::Id> openNodeStack; // IDs of nodes on the current path after each node insertion
  std::vector<std::size_t> depthStack; // same size as openNodeStack

  auto currentDepth = [&]() -> std::size_t {
    if (depthStack.empty()) return 0;
    return depthStack.back();
  };

  while (!tree.complete()) {
    // Enforce max depth if requested.
    if (maxDepth != 0 && currentDepth() >= maxDepth) {
      tree.createLeaf(LeafData{0});
      // Leaf insertion may backtrack; update stacks below.
    } else {
      rebuildEnabledRowsForCurrentPosition();

      impl_->selector.findSignificantColumn();

      if (!impl_->selector.significantColumnFound() || !impl_->selector.significantPartitionFound()) {
        tree.createLeaf(LeafData{0});
      } else {
        const auto nodeIdForCounts = static_cast<std::uint32_t>(tree.currentNodeID() < 0 ? 0 : tree.currentNodeID());
        const auto splitColumnIndex = static_cast<std::uint64_t>(impl_->selector.getSignificantColumnIndex());
        // Partition "one" is left, partition "two" is right.
        auto leftValues = impl_->selector.getFirstPartition();
        auto rightValues = impl_->selector.getSecondPartition();
        const auto countThreshold = nodeIdForCounts + 1;
        const auto leftCount = countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), leftValues);
        const auto rightCount = countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), rightValues);

        tree.createNode(modelbuilder::NodeData{splitColumnIndex, std::move(leftValues), std::move(rightValues), leftCount, rightCount});
      }
    }

    // Maintain a best-effort depth stack consistent with LeftTree's backtracking.
    // If current node is null, tree is complete.
    auto* cur = tree.getCurrentNode();
    if (!cur) break;

    // If we just created a node, it's the current node with no children yet.
    // Add it to the stack if not already.
    if (openNodeStack.empty() || openNodeStack.back() != cur->id) {
      // We only push when the current node has no children yet (newly created).
      if (!cur->left && !cur->right) {
        const std::size_t d = depthStack.empty() ? 1 : (depthStack.back() + 1);
        openNodeStack.push_back(cur->id);
        depthStack.push_back(d);
      } else {
        // Backtracked to an existing node; trim stacks to match.
        while (!openNodeStack.empty() && openNodeStack.back() != cur->id) {
          openNodeStack.pop_back();
          depthStack.pop_back();
        }
      }
    }
  }

  return tree;
}

std::uint64_t ModelBuilder::rowCount() const {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();
  return impl_->selector.getRowCount();
}

std::uint64_t ModelBuilder::columnCount() const {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();
  return impl_->selector.getColumnCount();
}

namespace {

std::string escapeDotLabel(std::string s) {
  // Graphviz "label" strings support C-like escapes; simplest is to escape backslash and quotes.
  std::string out;
  out.reserve(s.size());
  for (char ch : s) {
    if (ch == '\\' || ch == '"') out.push_back('\\');
    // Graphviz labels use the two-character sequence "\n" to denote a line break.
    // We allow callers to use real newlines when building the label.
    if (ch == '\n') out += "\\n";
    else out.push_back(ch);
  }
  return out;
}

template <class T>
std::string vecToString(const std::vector<T>& v, std::size_t maxItems = 32) {
  std::ostringstream oss;
  oss << "[";
  for (std::size_t i = 0; i < v.size() && i < maxItems; ++i) {
    if (i) oss << ",";
    oss << v[i];
  }
  if (v.size() > maxItems) oss << ",...";
  oss << "]";
  return oss.str();
}

} // namespace

void ModelBuilder::createGraphviz(const Tree& tree, const std::string& outputDotPath) const {
  std::ofstream out(outputDotPath);
  if (!out) {
    throw std::runtime_error("ModelBuilder::createGraphviz: unable to open output file: " + outputDotPath);
  }

  out << "digraph LeftTree {\n";
  out << "  rankdir=TB;\n";
  out << "  node [shape=box, fontname=\"Helvetica\"];\n";
  out << "  edge [fontname=\"Helvetica\"];\n";

  const auto* root = tree.root();
  if (!root) {
    out << "}\n";
    return;
  }

  // LeftTree uses sequential IDs: elementCount() is nextId_.
  for (std::size_t i = 0; i < tree.elementCount(); ++i) {
    const auto id = static_cast<Tree::Id>(i);
    auto type = tree.getElementType(id);
    if (!type.has_value()) continue;

    std::ostringstream label;
    label << "id=" << id;
    auto dataOpt = tree.getElementData(id);
    if (dataOpt.has_value()) {
      if (std::holds_alternative<Tree::NodeDataResult>(*dataOpt)) {
        const auto& [elemType, nd] = std::get<Tree::NodeDataResult>(*dataOpt);
        (void)elemType;
        label << "\nNode";
        if (nd.has_value()) {
          label << "\nsplitColumn=" << nd->splitColumnIndex();
          label << "\nleftCount=" << nd->leftPartitionCount();
          label << "\nleft=" << vecToString(nd->leftPartitionValues());
          label << "\nrightCount=" << nd->rightPartitionCount();
          label << "\nright=" << vecToString(nd->rightPartitionValues());
        } else {
          label << "\n(no data)";
        }
        out << "  n" << id << " [shape=box, label=\"" << escapeDotLabel(label.str()) << "\"];\n";
      } else {
        const auto& [elemType, lf] = std::get<Tree::LeafDataResult>(*dataOpt);
        (void)elemType;
        label << "\nLeaf";
        if (lf.has_value()) {
          label << "\nvalue=" << lf->placeholder();
        } else {
          label << "\n(no data)";
        }
        out << "  n" << id << " [shape=ellipse, label=\"" << escapeDotLabel(label.str()) << "\"];\n";
      }
    }
  }

  // Emit edges based on the stored structure.
  for (std::size_t i = 0; i < tree.elementCount(); ++i) {
    const auto id = static_cast<Tree::Id>(i);
    const auto* node = tree.getNode(id);
    if (!node) continue;
    if (node->left) {
      out << "  n" << id << " -> n" << node->left->id << " [label=\"L\"];\n";
    }
    if (node->right) {
      out << "  n" << id << " -> n" << node->right->id << " [label=\"R\"];\n";
    }
  }

  out << "}\n";
}

} // namespace modelbuilder

#include <ModelBuilder/ModelBuilder.hpp>

#include <ContingencyTable/FeatureSelector.h>

#include <algorithm>
#include <cctype>
#include <fstream>
#include <iomanip>
#include <limits>
#include <memory>
#include <sstream>
#include <stdexcept>

namespace modelbuilder {

struct ModelBuilder::Impl {
  ContingencyTableLib::FeatureSelector selector;

  std::string dataPath;
  bool loaded = false;

  std::size_t targetColumn = 0;

  // Row marker vector used by FeatureSelector::enabledRows(vector<uint32_t>&,...)
  std::vector<std::uint32_t> rowIndices;

  // Enabled columns bitmask for FeatureSelector::enabledColumns
  std::vector<std::uint32_t> enabledColumnsBitmask;
  bool hasAnalysisColumns = false;

  void ensureLoaded() const {
    if (!loaded) throw std::logic_error("ModelBuilder: call loadDataDir() before building");
  }

  static std::vector<std::uint32_t> makeBitmaskFromIndices(std::size_t numBits,
                                                          const std::vector<std::size_t>& indices) {
    const std::size_t numWords = (numBits + 31) / 32;
    std::vector<std::uint32_t> bm(numWords, 0);
    for (std::size_t idx : indices) {
      if (idx >= numBits) {
        throw std::out_of_range("ModelBuilder: column index out of range");
      }
      bm[idx / 32] |= (1u << (idx % 32));
    }
    return bm;
  }
};

ModelBuilder::ModelBuilder() : impl_(new Impl()) {}
ModelBuilder::~ModelBuilder() { delete impl_; }
ModelBuilder::ModelBuilder(ModelBuilder&& other) noexcept : impl_(other.impl_) { other.impl_ = nullptr; }
ModelBuilder& ModelBuilder::operator=(ModelBuilder&& other) noexcept {
  if (this == &other) return *this;
  delete impl_;
  impl_ = other.impl_;
  other.impl_ = nullptr;
  return *this;
}

void ModelBuilder::loadDataDir(const std::string& path) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->dataPath = path;
  impl_->selector.load(path);
  impl_->loaded = true;

  const auto rows = impl_->selector.getRowCount();
  if (rows > static_cast<std::uint64_t>(std::numeric_limits<std::size_t>::max())) {
    throw std::overflow_error("ModelBuilder: row count too large for internal buffers");
  }
  impl_->rowIndices.assign(static_cast<std::size_t>(rows), 0);
  if (!impl_->rowIndices.empty()) {
    // DataTable underlying ContingencyTable uses row 0 as header row.
    // Keep it permanently disabled in the marker scheme.
    impl_->rowIndices[0] = std::numeric_limits<std::uint32_t>::max();
  }
}

void ModelBuilder::setTargetColumn(std::size_t columnIndex) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->targetColumn = columnIndex;
  if (impl_->loaded) {
    if (columnIndex >= impl_->selector.getColumnCount()) {
      throw std::out_of_range("ModelBuilder: target column out of range");
    }
    impl_->selector.setTargetColumn(columnIndex);
  }
}

void ModelBuilder::setColumnAlpha(double alpha, bool applyBonferroni) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();
  impl_->selector.setColumnAlpha(alpha, applyBonferroni);
}

void ModelBuilder::setPartitionAlpha(double alpha, bool applyBonferroni) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();
  impl_->selector.setPartitionAlpha(alpha, applyBonferroni);
}

void ModelBuilder::setAnalysisColumns(const std::vector<std::size_t>& columnIndices) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();

  const auto cols = impl_->selector.getColumnCount();
  if (cols > static_cast<std::uint64_t>(std::numeric_limits<std::size_t>::max())) {
    throw std::overflow_error("ModelBuilder: column count too large for internal buffers");
  }
  impl_->enabledColumnsBitmask = Impl::makeBitmaskFromIndices(static_cast<std::size_t>(cols), columnIndices);
  impl_->hasAnalysisColumns = true;

  impl_->selector.enabledColumns(impl_->enabledColumnsBitmask.data(), static_cast<std::size_t>(cols));
}

ModelBuilder::Tree ModelBuilder::buildTree(std::size_t maxDepth) {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();

  if (impl_->targetColumn >= impl_->selector.getColumnCount()) {
    throw std::out_of_range("ModelBuilder: target column out of range");
  }
  impl_->selector.setTargetColumn(impl_->targetColumn);

  // If analysis columns not set, default to "all columns" and let FeatureSelector do its own exclusions
  // (typically it excludes target column internally).
  if (impl_->hasAnalysisColumns) {
    const auto cols = impl_->selector.getColumnCount();
    impl_->selector.enabledColumns(impl_->enabledColumnsBitmask.data(), static_cast<std::size_t>(cols));
  }

  Tree tree;

  auto countEnabledRowsAfterApplyingPartition = [&](std::uint32_t threshold,
                                                    std::size_t splitColumnIndex,
                                                    const std::vector<std::uint32_t>& allowedValues) -> std::uint64_t {
    // Take a copy so we can apply an additional filter without mutating the live marker state.
    auto tmp = impl_->rowIndices;
    impl_->selector.enabledRows(tmp, threshold, allowedValues, splitColumnIndex);
    std::uint64_t c = 0;
    for (std::size_t i = 1; i < tmp.size(); ++i) {
      if (tmp[i] == 0) ++c;
    }
    return c;
  };

  auto rebuildEnabledRowsForCurrentPosition = [&]() {
    // Recompute selector row state for the current insertion point by applying
    // the sequence of splits from the root down to the *parent* of the next element.
    // This avoids subtle inconsistencies when LeftTree backtracks from a fully-grown
    // left branch to a right branch.
    const auto* cur = tree.getCurrentNode();
    if (!cur) return;

    // Restore row marker state to what it looked like when we *arrived* at the current node.
    // Contract (as used by FeatureSelector::enabledRows(rowIndices,...)):
    // - When a node with id=N applies a partition filter, any row excluded is marked with value N.
    // - When backtracking to (or re-evaluating under) node N, we must re-enable all rows that were
    //   excluded by node N or any deeper node, i.e. clear markers >= N back to 0.
    const auto curIdU32 = static_cast<std::uint32_t>(cur->id);
    for (auto& m : impl_->rowIndices) {
      if (m >= curIdU32) m = 0;
    }

    // Keep DataTable header row permanently disabled in our marker scheme.
    if (!impl_->rowIndices.empty()) {
      impl_->rowIndices[0] = std::numeric_limits<std::uint32_t>::max();
    }

    // Collect the path nodes from root to current.
    std::vector<const Tree::Node*> path;
    for (const Tree::Node* n = cur; n != nullptr; ) {
      path.push_back(n);

      // Find parent by scanning ids downwards (IDs are sequential and parent is < child).
      const Tree::Node* parent = nullptr;
      for (Tree::Id pid = n->id - 1; pid >= 0; --pid) {
        const auto* cand = tree.getNode(pid);
        if (!cand) continue;
        // Use pointer identity (not just id) to avoid mismatches during construction.
        if ((cand->left && cand->left.get() == n) || (cand->right && cand->right.get() == n)) {
          parent = cand;
          break;
        }
      }
      n = parent;
    }
    std::reverse(path.begin(), path.end());

    // Apply each ancestor split on the way down, but only for ancestors of the current insertion node.
    // The current insertion node's own split has NOT been taken yet (we are about to decide
    // its left vs right child), so applying it here would incorrectly filter out rows.
    if (path.size() <= 1) return;
    for (std::size_t i = 0; i + 1 < path.size(); ++i) {
      const auto* n = path[i];
      if (!n->data.has_value()) continue;
      const auto& nd = *n->data;

      // Determine which branch we took from this node.
      const auto* child = path[i + 1];
      const bool tookLeft = (n->left && n->left.get() == child);

      // IMPORTANT: By contract, FeatureSelector partition "one" corresponds to the left branch
      // (LeftTree edge label "L") and partition "two" corresponds to the right branch.
      // NodeData stores these as leftPartitionValues/rightPartitionValues.
      const auto& allowed = tookLeft ? nd.leftPartitionValues() : nd.rightPartitionValues();

      // Use threshold == node id.
      // This means: before applying this node's whitelist, re-enable any rows that were previously
      // disabled at this node or deeper (marker >= nodeId).
      impl_->selector.enabledRows(impl_->rowIndices,
                                 static_cast<std::uint32_t>(n->id),
                                 allowed,
                                 static_cast<std::size_t>(nd.splitColumnIndex()));
    }

    // Finally, apply the *current node's* branch filter for the next insertion (left child first,
    // and after backtracking, right child). This is the critical step that makes the enabled rows
    // for the soon-to-be-created child match the parent's left/right partition counts.
    if (auto* insertionParent = tree.getCurrentNode(); insertionParent && insertionParent->data.has_value()) {
      const auto& nd = *insertionParent->data;
      const bool insertingLeft = (insertionParent->left == nullptr);
      const auto& allowed = insertingLeft ? nd.leftPartitionValues() : nd.rightPartitionValues();
      impl_->selector.enabledRows(impl_->rowIndices,
                                 static_cast<std::uint32_t>(insertionParent->id),
                                 allowed,
                                 static_cast<std::size_t>(nd.splitColumnIndex()));
    }
  };

  // LeftTree considers an empty tree "complete" (current node == nullptr). Seed a root element.
  // The root decision is based on feature selection on all currently enabled rows.
  impl_->selector.findSignificantColumn();
  if (!impl_->selector.significantColumnFound() || !impl_->selector.significantPartitionFound()) {
    if (!impl_->selector.significantColumnFound()) {
      tree.createLeaf(LeafData::noSignificantColumn(impl_->selector.getTargetCounts()));
    } else {
      tree.createLeaf(
          LeafData::noSignificantPartition(impl_->selector.getSignificantColumnIndex(),
                                           impl_->selector.getTargetCounts()));
    }
  } else {
    const auto nodeIdForCounts = static_cast<std::uint32_t>(tree.currentNodeID() < 0 ? 0 : tree.currentNodeID());
    const auto splitColumnIndex = static_cast<std::uint64_t>(impl_->selector.getSignificantColumnIndex());
    // Partition "one" is left, partition "two" is right.
    auto leftValues = impl_->selector.getFirstPartition();
    auto rightValues = impl_->selector.getSecondPartition();

    // Counts are defined as the number of rows reaching each branch (child) of this node.
    // Compute using the current enabled set (rows reaching this node) and applying the node's
    // own partition whitelist to a temporary marker vector.
    // When applying a hypothetical partition filter for counting purposes, we must not clear
    // any markers that represent the current node's arrival state. Since enabledRows() clears
    // markers >= threshold, use (nodeId + 1) here.
    const auto countThreshold = nodeIdForCounts + 1;
    const auto leftCount = countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), leftValues);
    const auto rightCount = countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), rightValues);

    tree.createNode(modelbuilder::NodeData{splitColumnIndex, std::move(leftValues), std::move(rightValues), leftCount, rightCount});
  }

  // Depth tracking aligned to insertion path. LeftTree stores its own path privately, so we track here.
  // We push depth when we create a node (descend), and pop when LeftTree backtracks after leaf insertion.
  // To detect backtracking we can observe currentNodeID changes, but simplest is to recompute via tree.getCurrentNode().
  std::vector<Tree::Id> openNodeStack; // IDs of nodes on the current path after each node insertion
  std::vector<std::size_t> depthStack; // same size as openNodeStack

  auto currentDepth = [&]() -> std::size_t {
    if (depthStack.empty()) return 0;
    return depthStack.back();
  };

  while (!tree.complete()) {
    // Enforce max depth if requested.
    if (maxDepth != 0 && currentDepth() >= maxDepth) {
      // Depth-limited leaf; treat as "no significant column" for now.
      rebuildEnabledRowsForCurrentPosition();
      impl_->selector.findSignificantColumn();
      tree.createLeaf(LeafData::noSignificantColumn(impl_->selector.getTargetCounts()));
      // Leaf insertion may backtrack; update stacks below.
    } else {
      rebuildEnabledRowsForCurrentPosition();

      impl_->selector.findSignificantColumn();

      if (!impl_->selector.significantColumnFound() || !impl_->selector.significantPartitionFound()) {
        if (!impl_->selector.significantColumnFound()) {
          tree.createLeaf(LeafData::noSignificantColumn(impl_->selector.getTargetCounts()));
        } else {
          tree.createLeaf(LeafData::noSignificantPartition(impl_->selector.getSignificantColumnIndex(),
                                                          impl_->selector.getTargetCounts()));
        }
      } else {
        const auto nodeIdForCounts = static_cast<std::uint32_t>(tree.currentNodeID() < 0 ? 0 : tree.currentNodeID());
        const auto splitColumnIndex = static_cast<std::uint64_t>(impl_->selector.getSignificantColumnIndex());
        // Partition "one" is left, partition "two" is right.
        auto leftValues = impl_->selector.getFirstPartition();
        auto rightValues = impl_->selector.getSecondPartition();
        const auto countThreshold = nodeIdForCounts + 1;
        const auto leftCount = countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), leftValues);
        const auto rightCount = countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), rightValues);

        tree.createNode(modelbuilder::NodeData{splitColumnIndex, std::move(leftValues), std::move(rightValues), leftCount, rightCount});
      }
    }

    // Maintain a best-effort depth stack consistent with LeftTree's backtracking.
    // If current node is null, tree is complete.
    auto* cur = tree.getCurrentNode();
    if (!cur) break;

    // If we just created a node, it's the current node with no children yet.
    // Add it to the stack if not already.
    if (openNodeStack.empty() || openNodeStack.back() != cur->id) {
      // We only push when the current node has no children yet (newly created).
      if (!cur->left && !cur->right) {
        const std::size_t d = depthStack.empty() ? 1 : (depthStack.back() + 1);
        openNodeStack.push_back(cur->id);
        depthStack.push_back(d);
      } else {
        // Backtracked to an existing node; trim stacks to match.
        while (!openNodeStack.empty() && openNodeStack.back() != cur->id) {
          openNodeStack.pop_back();
          depthStack.pop_back();
        }
      }
    }
  }

  return tree;
}

std::uint64_t ModelBuilder::rowCount() const {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();
  return impl_->selector.getRowCount();
}

std::uint64_t ModelBuilder::columnCount() const {
  if (!impl_) throw std::logic_error("ModelBuilder: moved-from instance");
  impl_->ensureLoaded();
  return impl_->selector.getColumnCount();
}

namespace {

std::string escapeDotLabel(std::string s) {
  // Graphviz "label" strings support C-like escapes; simplest is to escape backslash and quotes.
  std::string out;
  out.reserve(s.size());
  for (char ch : s) {
    if (ch == '\\' || ch == '"') out.push_back('\\');
    // Graphviz labels use the two-character sequence "\n" to denote a line break.
    // We allow callers to use real newlines when building the label.
    if (ch == '\n') out += "\\n";
    else out.push_back(ch);
  }
  return out;
}

template <class T>
std::string vecToString(const std::vector<T>& v, std::size_t maxItems = 32) {
  std::ostringstream oss;
  oss << "[";
  for (std::size_t i = 0; i < v.size() && i < maxItems; ++i) {
    if (i) oss << ",";
    oss << v[i];
  }
  if (v.size() > maxItems) oss << ",...";
  oss << "]";
  return oss.str();
}

} // namespace

void ModelBuilder::createGraphviz(const Tree& tree, const std::string& outputDotPath) const {
  std::ofstream out(outputDotPath);
  if (!out) {
    throw std::runtime_error("ModelBuilder::createGraphviz: unable to open output file: " + outputDotPath);
  }

  out << "digraph LeftTree {\n";
  out << "  rankdir=TB;\n";
  out << "  node [shape=box, fontname=\"Helvetica\"];\n";
  out << "  edge [fontname=\"Helvetica\"];\n";

  const auto* root = tree.root();
  if (!root) {
    out << "}\n";
    return;
  }

  // LeftTree uses sequential IDs: elementCount() is nextId_.
  for (std::size_t i = 0; i < tree.elementCount(); ++i) {
    const auto id = static_cast<Tree::Id>(i);
    auto type = tree.getElementType(id);
    if (!type.has_value()) continue;

    std::ostringstream label;
    label << "id=" << id;
    auto dataOpt = tree.getElementData(id);
    if (dataOpt.has_value()) {
      if (std::holds_alternative<Tree::NodeDataResult>(*dataOpt)) {
        const auto& [elemType, nd] = std::get<Tree::NodeDataResult>(*dataOpt);
        (void)elemType;
        label << "\nNode";
        if (nd.has_value()) {
          label << "\nsplitColumn=" << nd->splitColumnIndex();
          label << "\nleftCount=" << nd->leftPartitionCount();
          label << "\nleft=" << vecToString(nd->leftPartitionValues());
          label << "\nrightCount=" << nd->rightPartitionCount();
          label << "\nright=" << vecToString(nd->rightPartitionValues());
        } else {
          label << "\n(no data)";
        }
        out << "  n" << id << " [shape=box, label=\"" << escapeDotLabel(label.str()) << "\"];\n";
      } else {
        const auto& [elemType, lf] = std::get<Tree::LeafDataResult>(*dataOpt);
        (void)elemType;
        label << "\nLeaf";
        if (lf.has_value()) {
          label << "\nsplitColumn=" << lf->splitColumnIndexOrMinusOne();
          label << "\ntargetCounts:";
          if (lf->targetCounts().empty()) {
            label << "\n  (empty)";
          } else {
            for (const auto& [k, v] : lf->targetCounts()) {
              label << "\n  " << k << ":" << v;
            }
          }
        } else {
          label << "\n(no data)";
        }
        out << "  n" << id << " [shape=ellipse, label=\"" << escapeDotLabel(label.str()) << "\"];\n";
      }
    }
  }

  // Emit edges based on the stored structure.
  for (std::size_t i = 0; i < tree.elementCount(); ++i) {
    const auto id = static_cast<Tree::Id>(i);
    const auto* node = tree.getNode(id);
    if (!node) continue;
    if (node->left) {
      out << "  n" << id << " -> n" << node->left->id << " [label=\"L\"];\n";
    }
    if (node->right) {
      out << "  n" << id << " -> n" << node->right->id << " [label=\"R\"];\n";
    }
  }

  out << "}\n";
}

} // namespace modelbuilder

#include <ModelBuilder/MultiModelBuilder.hpp>

#include <algorithm>
#include <atomic>
#include <bit>
#include <condition_variable>
#include <cstddef>
#include <cstdint>
#include <filesystem>
#include <fstream>
#include <mutex>
#include <optional>
#include <queue>
#include <sstream>
#include <stdexcept>
#include <string>
#include <thread>
#include <utility>
#include <vector>

namespace modelbuilder {

namespace {
struct BuiltTree {
  std::uint64_t targetColumn = 0;
  std::string bytes; // serialized TreeBuilder payload
};

class BlockingQueue {
public:
  void push(BuiltTree v) {
    {
      std::lock_guard<std::mutex> lk(mu_);
      q_.push(std::move(v));
    }
    cv_.notify_one();
  }

  // Returns false when closed and drained.
  bool pop(BuiltTree& out) {
    std::unique_lock<std::mutex> lk(mu_);
    cv_.wait(lk, [&]() { return closed_ || !q_.empty(); });
    if (q_.empty()) return false;
    out = std::move(q_.front());
    q_.pop();
    return true;
  }

  void close() {
    {
      std::lock_guard<std::mutex> lk(mu_);
      closed_ = true;
    }
    cv_.notify_all();
  }

private:
  std::mutex mu_;
  std::condition_variable cv_;
  std::queue<BuiltTree> q_;
  bool closed_ = false;
};

static std::vector<std::size_t> analysisExcludingTarget(const std::vector<std::size_t>& base,
                                                        std::size_t target) {
  std::vector<std::size_t> out;
  out.reserve(base.size());
  for (auto c : base) {
    if (c == target) continue;
    out.push_back(c);
  }
  return out;
}

} // namespace

std::string MultiModelBuilder::treesPath_(const std::string& outputDir) {
  return (std::filesystem::path{outputDir} / "mb_trees.bin").string();
}

std::string MultiModelBuilder::mapPath_(const std::string& outputDir) {
  return (std::filesystem::path{outputDir} / "mb_map.bin").string();
}

void MultiModelBuilder::writeU8_(std::ostream& out, std::uint8_t v) {
  out.put(static_cast<char>(v));
  if (!out) throw std::runtime_error("MultiModelBuilder: writeU8 failed");
}

std::uint8_t MultiModelBuilder::readU8_(std::istream& in) {
  const int c = in.get();
  if (c == std::char_traits<char>::eof()) throw std::runtime_error("MultiModelBuilder: readU8 failed");
  return static_cast<std::uint8_t>(c);
}

void MultiModelBuilder::writeU64BE_(std::ostream& out, std::uint64_t v) {
  for (int i = 7; i >= 0; --i) writeU8_(out, static_cast<std::uint8_t>((v >> (i * 8)) & 0xFFu));
}

std::uint64_t MultiModelBuilder::readU64BE_(std::istream& in) {
  std::uint64_t v = 0;
  for (int i = 0; i < 8; ++i) v = (v << 8) | readU8_(in);
  return v;
}

void MultiModelBuilder::writeF64BE_(std::ostream& out, double d) {
  const std::uint64_t bits = std::bit_cast<std::uint64_t>(d);
  writeU64BE_(out, bits);
}

double MultiModelBuilder::readF64BE_(std::istream& in) {
  const std::uint64_t bits = readU64BE_(in);
  return std::bit_cast<double>(bits);
}

void MultiModelBuilder::writeBool_(std::ostream& out, bool b) { writeU8_(out, b ? 1u : 0u); }

bool MultiModelBuilder::readBool_(std::istream& in) {
  const auto v = readU8_(in);
  if (v != 0u && v != 1u) throw std::runtime_error("MultiModelBuilder: invalid boolean value");
  return v == 1u;
}

void MultiModelBuilder::writeString_(std::ostream& out, const std::string& s) {
  writeU64BE_(out, static_cast<std::uint64_t>(s.size()));
  out.write(s.data(), static_cast<std::streamsize>(s.size()));
  if (!out) throw std::runtime_error("MultiModelBuilder: writeString failed");
}

std::string MultiModelBuilder::readString_(std::istream& in) {
  const auto n = readU64BE_(in);
  std::string s;
  s.resize(static_cast<std::size_t>(n));
  if (n > 0) {
    in.read(s.data(), static_cast<std::streamsize>(s.size()));
    if (!in) throw std::runtime_error("MultiModelBuilder: readString failed");
  }
  return s;
}

MultiModelBuilder MultiModelBuilder::buildAndWrite(const std::string& parsedDir,
                                                   const std::string& outputDir,
                                                   const std::vector<std::size_t>& targetColumns,
                                                   std::size_t maxDepth,
                                                   double columnAlpha,
                                                   bool columnAlphaApplyBonferroni,
                                                   double partitionAlpha,
                                                   bool partitionAlphaApplyBonferroni,
                                                   const std::vector<std::size_t>& analysisColumns,
                                                   std::size_t threadCount) {
  if (threadCount == 0) threadCount = 1;

  std::filesystem::create_directories(outputDir);

  const auto treesPath = treesPath_(outputDir);
  std::ofstream treesOut(treesPath, std::ios::binary | std::ios::trunc);
  if (!treesOut) throw std::runtime_error("MultiModelBuilder: failed to open mb_trees.bin for write");

  BlockingQueue q;
  std::atomic<std::size_t> next{0};

  // Writer state
  std::mutex mapMu;
  std::vector<std::pair<std::uint64_t, std::uint64_t>> mapPairs;
  mapPairs.reserve(targetColumns.size());

  auto writer = std::thread([&]() {
    BuiltTree item;
    while (q.pop(item)) {
      const std::uint64_t off = static_cast<std::uint64_t>(treesOut.tellp());
      // record: u64 len + bytes
      writeU64BE_(treesOut, static_cast<std::uint64_t>(item.bytes.size()));
      if (!item.bytes.empty()) {
        treesOut.write(item.bytes.data(), static_cast<std::streamsize>(item.bytes.size()));
      }
      if (!treesOut) throw std::runtime_error("MultiModelBuilder: failed writing mb_trees.bin");

      {
        std::lock_guard<std::mutex> lk(mapMu);
        mapPairs.emplace_back(item.targetColumn, off);
      }
    }
  });

  auto workerFn = [&]() {
    while (true) {
      const auto i = next.fetch_add(1);
      if (i >= targetColumns.size()) break;
      const auto tgt = targetColumns[i];

      const auto perTreeAnalysis = analysisExcludingTarget(analysisColumns, tgt);

      auto artifact = TreeBuilder::buildFromDataDir(parsedDir,
                                                   tgt,
                                                   maxDepth,
                                                   columnAlpha,
                                                   columnAlphaApplyBonferroni,
                                                   partitionAlpha,
                                                   partitionAlphaApplyBonferroni,
                                                   perTreeAnalysis);

      std::ostringstream tmp(std::ios::binary);
      artifact.serialize(tmp);
      q.push(BuiltTree{static_cast<std::uint64_t>(tgt), tmp.str()});
    }
  };

  std::vector<std::thread> workers;
  workers.reserve(threadCount);
  for (std::size_t t = 0; t < threadCount; ++t) workers.emplace_back(workerFn);

  for (auto& th : workers) th.join();
  q.close();
  writer.join();

  // Sort by target column for deterministic output, and validate uniqueness.
  std::sort(mapPairs.begin(), mapPairs.end(), [](auto& a, auto& b) {
    if (a.first != b.first) return a.first < b.first;
    return a.second < b.second;
  });

  for (std::size_t i = 1; i < mapPairs.size(); ++i) {
    if (mapPairs[i - 1].first == mapPairs[i].first) {
      throw std::runtime_error("MultiModelBuilder: duplicate targetColumn in map");
    }
  }

  // Write mb_map.bin as length+bytes.
  const auto mapPath = mapPath_(outputDir);
  std::ofstream mapOut(mapPath, std::ios::binary | std::ios::trunc);
  if (!mapOut) throw std::runtime_error("MultiModelBuilder: failed to open mb_map.bin for write");

  const std::uint64_t payloadLen = static_cast<std::uint64_t>(mapPairs.size()) * 16ull;
  writeU64BE_(mapOut, payloadLen);
  for (const auto& [tc, off] : mapPairs) {
    writeU64BE_(mapOut, tc);
    writeU64BE_(mapOut, off);
  }
  if (!mapOut) throw std::runtime_error("MultiModelBuilder: failed writing mb_map.bin");

  MultiModelBuilder mb;
  mb.parsedDir_ = parsedDir;
  mb.outputDir_ = outputDir;
  mb.maxDepth_ = maxDepth;
  mb.columnAlpha_ = columnAlpha;
  mb.columnAlphaApplyBonferroni_ = columnAlphaApplyBonferroni;
  mb.partitionAlpha_ = partitionAlpha;
  mb.partitionAlphaApplyBonferroni_ = partitionAlphaApplyBonferroni;
  for (const auto& [tc, off] : mapPairs) mb.targetToOffset_.emplace(tc, off);

  return mb;
}

void MultiModelBuilder::loadMap() {
  targetToOffset_.clear();

  const auto mapPath = mapPath_(outputDir_);
  std::ifstream in(mapPath, std::ios::binary);
  if (!in) throw std::runtime_error("MultiModelBuilder: failed to open mb_map.bin");

  const std::uint64_t payloadLen = readU64BE_(in);
  if (payloadLen % 16ull != 0ull) throw std::runtime_error("MultiModelBuilder: invalid mb_map.bin payload length");

  const std::uint64_t pairCount = payloadLen / 16ull;
  for (std::uint64_t i = 0; i < pairCount; ++i) {
    const auto tc = readU64BE_(in);
    const auto off = readU64BE_(in);
    targetToOffset_.emplace(tc, off);
  }

  if (!in) throw std::runtime_error("MultiModelBuilder: failed reading mb_map.bin");
}

TreeBuilder MultiModelBuilder::getTree(std::uint64_t targetColumn) const {
  const auto it = targetToOffset_.find(targetColumn);
  if (it == targetToOffset_.end()) {
    throw std::out_of_range("MultiModelBuilder::getTree: target column not found");
  }

  const auto treesPath = treesPath_(outputDir_);
  std::ifstream in(treesPath, std::ios::binary);
  if (!in) throw std::runtime_error("MultiModelBuilder::getTree: failed to open mb_trees.bin");

  in.seekg(static_cast<std::streamoff>(it->second));
  if (!in) throw std::runtime_error("MultiModelBuilder::getTree: failed to seek to tree offset");

  const std::uint64_t len = readU64BE_(in);
  std::string blob;
  blob.resize(static_cast<std::size_t>(len));
  if (len > 0) {
    in.read(blob.data(), static_cast<std::streamsize>(blob.size()));
    if (!in) throw std::runtime_error("MultiModelBuilder::getTree: failed reading tree bytes");
  }

  std::istringstream tmp(blob, std::ios::binary);
  return TreeBuilder::deserialize(tmp);
}

void MultiModelBuilder::serialize(std::ostream& out) const {
  // length+bytes overall not required here; we just provide a deterministic binary encoding.
  writeString_(out, parsedDir_);
  writeString_(out, outputDir_);
  writeU64BE_(out, static_cast<std::uint64_t>(maxDepth_));
  writeF64BE_(out, columnAlpha_);
  writeBool_(out, columnAlphaApplyBonferroni_);
  writeF64BE_(out, partitionAlpha_);
  writeBool_(out, partitionAlphaApplyBonferroni_);

  // Store target->offset map in the object serialization as well (so deserialize does not *require*
  // reading mb_map.bin first), but still keep loadMap() available.
  writeU64BE_(out, static_cast<std::uint64_t>(targetToOffset_.size()));
  // Serialize in sorted order for determinism.
  std::vector<std::pair<std::uint64_t, std::uint64_t>> pairs;
  pairs.reserve(targetToOffset_.size());
  for (const auto& kv : targetToOffset_) pairs.emplace_back(kv.first, kv.second);
  std::sort(pairs.begin(), pairs.end());
  for (const auto& [tc, off] : pairs) {
    writeU64BE_(out, tc);
    writeU64BE_(out, off);
  }

  if (!out) throw std::runtime_error("MultiModelBuilder::serialize failed");
}

MultiModelBuilder MultiModelBuilder::deserialize(std::istream& in) {
  MultiModelBuilder mb;
  mb.parsedDir_ = readString_(in);
  mb.outputDir_ = readString_(in);
  mb.maxDepth_ = static_cast<std::size_t>(readU64BE_(in));
  mb.columnAlpha_ = readF64BE_(in);
  mb.columnAlphaApplyBonferroni_ = readBool_(in);
  mb.partitionAlpha_ = readF64BE_(in);
  mb.partitionAlphaApplyBonferroni_ = readBool_(in);

  const std::uint64_t n = readU64BE_(in);
  for (std::uint64_t i = 0; i < n; ++i) {
    const auto tc = readU64BE_(in);
    const auto off = readU64BE_(in);
    mb.targetToOffset_.emplace(tc, off);
  }

  if (!in) throw std::runtime_error("MultiModelBuilder::deserialize failed");
  return mb;
}

} // namespace modelbuilder

#include <ModelBuilder/TreeBuilder.hpp>

#include <ContingencyTable/FeatureSelector.h>

#include <limits>
#include <stdexcept>

namespace modelbuilder {

namespace {
std::vector<std::uint32_t> makeBitmaskFromIndices(std::size_t numBits, const std::vector<std::size_t>& indices) {
  const std::size_t numWords = (numBits + 31) / 32;
  std::vector<std::uint32_t> bm(numWords, 0);
  for (std::size_t idx : indices) {
    if (idx >= numBits) {
      throw std::out_of_range("TreeBuilder: column index out of range");
    }
    bm[idx / 32] |= (1u << (idx % 32));
  }
  return bm;
}
} // namespace

TreeBuilder TreeBuilder::buildFromDataDir(const std::string& parsedDir,
                                         std::size_t targetColumn,
                                         std::size_t maxDepth,
                                         double columnAlpha,
                                         bool columnAlphaApplyBonferroni,
                                         double partitionAlpha,
                                         bool partitionAlphaApplyBonferroni,
                                         const std::vector<std::size_t>& analysisColumns) {
  ContingencyTableLib::FeatureSelector selector;
  selector.load(parsedDir);

  const auto rows = selector.getRowCount();
  if (rows > static_cast<std::uint64_t>(std::numeric_limits<std::size_t>::max())) {
    throw std::overflow_error("TreeBuilder: row count too large for internal buffers");
  }
  std::vector<std::uint32_t> rowIndices(static_cast<std::size_t>(rows), 0);
  if (!rowIndices.empty()) {
    // DataTable underlying ContingencyTable uses row 0 as header row.
    rowIndices[0] = std::numeric_limits<std::uint32_t>::max();
  }

  if (targetColumn >= selector.getColumnCount()) {
    throw std::out_of_range("TreeBuilder: target column out of range");
  }
  selector.setTargetColumn(targetColumn);

  selector.setColumnAlpha(columnAlpha, columnAlphaApplyBonferroni);
  selector.setPartitionAlpha(partitionAlpha, partitionAlphaApplyBonferroni);

  // Build-time only: optionally constrain split candidates.
  if (!analysisColumns.empty()) {
    const auto cols = selector.getColumnCount();
    if (cols > static_cast<std::uint64_t>(std::numeric_limits<std::size_t>::max())) {
      throw std::overflow_error("TreeBuilder: column count too large for internal buffers");
    }
    auto bm = makeBitmaskFromIndices(static_cast<std::size_t>(cols), analysisColumns);
    selector.enabledColumns(bm.data(), static_cast<std::size_t>(cols));
  }

  Tree tree;

  auto countEnabledRowsAfterApplyingPartition = [&](std::uint32_t threshold,
                                                    std::size_t splitColumnIndex,
                                                    const std::vector<std::uint32_t>& allowedValues) -> std::uint64_t {
    // Take a copy so we can apply an additional filter without mutating the live marker state.
    auto tmp = rowIndices;
    selector.enabledRows(tmp, threshold, allowedValues, splitColumnIndex);
    std::uint64_t c = 0;
    for (std::size_t i = 1; i < tmp.size(); ++i) {
      if (tmp[i] == 0) ++c;
    }
    return c;
  };

  auto rebuildEnabledRowsForCurrentPosition = [&]() {
    // Recompute selector row state for the current insertion point by applying
    // the sequence of splits from the root down to the *parent* of the next element.
    // This matches ModelBuilder::buildTree().
    const auto* cur = tree.getCurrentNode();
    if (!cur) return;

    // Clear markers >= current node id.
    const auto curIdU32 = static_cast<std::uint32_t>(cur->id);
    for (auto& m : rowIndices) {
      if (m >= curIdU32) m = 0;
    }
    if (!rowIndices.empty()) {
      rowIndices[0] = std::numeric_limits<std::uint32_t>::max();
    }

    // Collect path from root to current.
    std::vector<const Tree::Node*> path;
    for (const Tree::Node* n = cur; n != nullptr; ) {
      path.push_back(n);
      const Tree::Node* parent = nullptr;
      for (Tree::Id pid = n->id - 1; pid >= 0; --pid) {
        const auto* cand = tree.getNode(pid);
        if (!cand) continue;
        if ((cand->left && cand->left.get() == n) || (cand->right && cand->right.get() == n)) {
          parent = cand;
          break;
        }
      }
      n = parent;
    }
    std::reverse(path.begin(), path.end());

    if (path.size() <= 1) return;
    for (std::size_t i = 0; i + 1 < path.size(); ++i) {
      const auto* n = path[i];
      if (!n->data.has_value()) continue;
      const auto& nd = *n->data;
      const auto* child = path[i + 1];
      const bool tookLeft = (n->left && n->left.get() == child);
      const auto& allowed = tookLeft ? nd.leftPartitionValues() : nd.rightPartitionValues();
      selector.enabledRows(rowIndices,
                          static_cast<std::uint32_t>(n->id),
                          allowed,
                          static_cast<std::size_t>(nd.splitColumnIndex()));
    }

    if (auto* insertionParent = tree.getCurrentNode(); insertionParent && insertionParent->data.has_value()) {
      const auto& nd = *insertionParent->data;
      const bool insertingLeft = (insertionParent->left == nullptr);
      const auto& allowed = insertingLeft ? nd.leftPartitionValues() : nd.rightPartitionValues();
      selector.enabledRows(rowIndices,
                          static_cast<std::uint32_t>(insertionParent->id),
                          allowed,
                          static_cast<std::size_t>(nd.splitColumnIndex()));
    }
  };

  // Seed a root element.
  selector.findSignificantColumn();
  if (!selector.significantColumnFound() || !selector.significantPartitionFound()) {
    tree.createLeaf(LeafData{0});
  } else {
    const auto nodeIdForCounts = static_cast<std::uint32_t>(tree.currentNodeID() < 0 ? 0 : tree.currentNodeID());
    const auto splitColumnIndex = static_cast<std::uint64_t>(selector.getSignificantColumnIndex());
    auto leftValues = selector.getFirstPartition();
    auto rightValues = selector.getSecondPartition();
    const auto countThreshold = nodeIdForCounts + 1;
    const auto leftCount =
      countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), leftValues);
    const auto rightCount =
      countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), rightValues);

    tree.createNode(NodeData{splitColumnIndex, std::move(leftValues), std::move(rightValues), leftCount, rightCount});
  }

  // Depth tracking aligned to insertion path.
  std::vector<Tree::Id> openNodeStack;
  std::vector<std::size_t> depthStack;
  auto currentDepth = [&]() -> std::size_t {
    if (depthStack.empty()) return 0;
    return depthStack.back();
  };

  while (!tree.complete()) {
    if (maxDepth != 0 && currentDepth() >= maxDepth) {
      tree.createLeaf(LeafData{0});
    } else {
      rebuildEnabledRowsForCurrentPosition();
      selector.findSignificantColumn();

      if (!selector.significantColumnFound() || !selector.significantPartitionFound()) {
        tree.createLeaf(LeafData{0});
      } else {
        const auto nodeIdForCounts = static_cast<std::uint32_t>(tree.currentNodeID() < 0 ? 0 : tree.currentNodeID());
        const auto splitColumnIndex = static_cast<std::uint64_t>(selector.getSignificantColumnIndex());
        auto leftValues = selector.getFirstPartition();
        auto rightValues = selector.getSecondPartition();

        const auto countThreshold = nodeIdForCounts + 1;
        const auto leftCount =
          countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), leftValues);
        const auto rightCount =
          countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), rightValues);

        tree.createNode(NodeData{splitColumnIndex,
                                std::move(leftValues),
                                std::move(rightValues),
                                leftCount,
                                rightCount});
      }
    }

    auto* cur = tree.getCurrentNode();
    if (!cur) break;

    if (openNodeStack.empty() || openNodeStack.back() != cur->id) {
      if (!cur->left && !cur->right) {
        const std::size_t d = depthStack.empty() ? 1 : (depthStack.back() + 1);
        openNodeStack.push_back(cur->id);
        depthStack.push_back(d);
      } else {
        while (!openNodeStack.empty() && openNodeStack.back() != cur->id) {
          openNodeStack.pop_back();
          depthStack.pop_back();
        }
      }
    }
  }

  return TreeBuilder{targetColumn,
                     maxDepth,
                     columnAlpha,
                     columnAlphaApplyBonferroni,
                     partitionAlpha,
                     partitionAlphaApplyBonferroni,
                     std::move(tree)};
}

} // namespace modelbuilder

#include <ModelBuilder/TreeBuilder.hpp>

#include <ContingencyTable/FeatureSelector.h>

#include <limits>
#include <stdexcept>

namespace modelbuilder {

namespace {
std::vector<std::uint32_t> makeBitmaskFromIndices(std::size_t numBits, const std::vector<std::size_t>& indices) {
  const std::size_t numWords = (numBits + 31) / 32;
  std::vector<std::uint32_t> bm(numWords, 0);
  for (std::size_t idx : indices) {
    if (idx >= numBits) {
      throw std::out_of_range("TreeBuilder: column index out of range");
    }
    bm[idx / 32] |= (1u << (idx % 32));
  }
  return bm;
}
} // namespace

TreeBuilder TreeBuilder::buildFromDataDir(const std::string& parsedDir,
                                         std::size_t targetColumn,
                                         std::size_t maxDepth,
                                         double columnAlpha,
                                         bool columnAlphaApplyBonferroni,
                                         double partitionAlpha,
                                         bool partitionAlphaApplyBonferroni,
                                         const std::vector<std::size_t>& analysisColumns) {
  ContingencyTableLib::FeatureSelector selector;
  selector.load(parsedDir);

  const auto rows = selector.getRowCount();
  if (rows > static_cast<std::uint64_t>(std::numeric_limits<std::size_t>::max())) {
    throw std::overflow_error("TreeBuilder: row count too large for internal buffers");
  }
  std::vector<std::uint32_t> rowIndices(static_cast<std::size_t>(rows), 0);
  if (!rowIndices.empty()) {
    // DataTable underlying ContingencyTable uses row 0 as header row.
    rowIndices[0] = std::numeric_limits<std::uint32_t>::max();
  }

  if (targetColumn >= selector.getColumnCount()) {
    throw std::out_of_range("TreeBuilder: target column out of range");
  }
  selector.setTargetColumn(targetColumn);

  selector.setColumnAlpha(columnAlpha, columnAlphaApplyBonferroni);
  selector.setPartitionAlpha(partitionAlpha, partitionAlphaApplyBonferroni);

  // Build-time only: configure split candidate columns.
  // FeatureSelector requires enabledColumns() to be called before findSignificantColumn().
  //
  // If the caller provides an analysis column list, use it verbatim.
  // Otherwise, default to enabling all columns EXCEPT the target column.
  const auto colsU64 = selector.getColumnCount();
  if (colsU64 > static_cast<std::uint64_t>(std::numeric_limits<std::size_t>::max())) {
    throw std::overflow_error("TreeBuilder: column count too large for internal buffers");
  }
  const auto cols = static_cast<std::size_t>(colsU64);

  std::vector<std::uint32_t> enabledColumnsBitmask;
  if (!analysisColumns.empty()) {
    enabledColumnsBitmask = makeBitmaskFromIndices(cols, analysisColumns);
  } else {
    // Enable all columns.
    enabledColumnsBitmask.assign((cols + 31) / 32, 0xFFFFFFFFu);
    // Clear any padding bits above cols.
    const std::size_t extraBits = enabledColumnsBitmask.size() * 32 - cols;
    if (extraBits != 0) {
      enabledColumnsBitmask.back() >>= extraBits;
    }
    // Always exclude the target column from split candidates.
    if (targetColumn < cols) {
      enabledColumnsBitmask[targetColumn / 32] &= ~(1u << (targetColumn % 32));
    }
  }
  selector.enabledColumns(enabledColumnsBitmask.data(), cols);

  Tree tree;

  auto countEnabledRowsAfterApplyingPartition = [&](std::uint32_t threshold,
                                                    std::size_t splitColumnIndex,
                                                    const std::vector<std::uint32_t>& allowedValues) -> std::uint64_t {
    // Take a copy so we can apply an additional filter without mutating the live marker state.
    auto tmp = rowIndices;
    selector.enabledRows(tmp, threshold, allowedValues, splitColumnIndex);
    std::uint64_t c = 0;
    for (std::size_t i = 1; i < tmp.size(); ++i) {
      if (tmp[i] == 0) ++c;
    }
    return c;
  };

  auto rebuildEnabledRowsForCurrentPosition = [&]() {
    // Recompute selector row state for the current insertion point by applying
    // the sequence of splits from the root down to the *parent* of the next element.
    // This matches ModelBuilder::buildTree().
    const auto* cur = tree.getCurrentNode();
    if (!cur) return;

    // Clear markers >= current node id.
    const auto curIdU32 = static_cast<std::uint32_t>(cur->id);
    for (auto& m : rowIndices) {
      if (m >= curIdU32) m = 0;
    }
    if (!rowIndices.empty()) {
      rowIndices[0] = std::numeric_limits<std::uint32_t>::max();
    }

    // Collect path from root to current.
    std::vector<const Tree::Node*> path;
    for (const Tree::Node* n = cur; n != nullptr; ) {
      path.push_back(n);
      const Tree::Node* parent = nullptr;
      for (Tree::Id pid = n->id - 1; pid >= 0; --pid) {
        const auto* cand = tree.getNode(pid);
        if (!cand) continue;
        if ((cand->left && cand->left.get() == n) || (cand->right && cand->right.get() == n)) {
          parent = cand;
          break;
        }
      }
      n = parent;
    }
    std::reverse(path.begin(), path.end());

    if (path.size() <= 1) return;
    for (std::size_t i = 0; i + 1 < path.size(); ++i) {
      const auto* n = path[i];
      if (!n->data.has_value()) continue;
      const auto& nd = *n->data;
      const auto* child = path[i + 1];
      const bool tookLeft = (n->left && n->left.get() == child);
      const auto& allowed = tookLeft ? nd.leftPartitionValues() : nd.rightPartitionValues();
      selector.enabledRows(rowIndices,
                          static_cast<std::uint32_t>(n->id),
                          allowed,
                          static_cast<std::size_t>(nd.splitColumnIndex()));
    }

    if (auto* insertionParent = tree.getCurrentNode(); insertionParent && insertionParent->data.has_value()) {
      const auto& nd = *insertionParent->data;
      const bool insertingLeft = (insertionParent->left == nullptr);
      const auto& allowed = insertingLeft ? nd.leftPartitionValues() : nd.rightPartitionValues();
      selector.enabledRows(rowIndices,
                          static_cast<std::uint32_t>(insertionParent->id),
                          allowed,
                          static_cast<std::size_t>(nd.splitColumnIndex()));
    }
  };

  // Seed a root element.
  selector.findSignificantColumn();
  if (!selector.significantColumnFound() || !selector.significantPartitionFound()) {
    if (!selector.significantColumnFound()) {
      tree.createLeaf(LeafData::noSignificantColumn(selector.getTargetCounts()));
    } else {
      tree.createLeaf(LeafData::noSignificantPartition(selector.getSignificantColumnIndex(),
                                                       selector.getTargetCounts()));
    }
  } else {
    const auto nodeIdForCounts = static_cast<std::uint32_t>(tree.currentNodeID() < 0 ? 0 : tree.currentNodeID());
    const auto splitColumnIndex = static_cast<std::uint64_t>(selector.getSignificantColumnIndex());
    auto leftValues = selector.getFirstPartition();
    auto rightValues = selector.getSecondPartition();
    const auto countThreshold = nodeIdForCounts + 1;
    const auto leftCount =
      countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), leftValues);
    const auto rightCount =
      countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), rightValues);

    tree.createNode(NodeData{splitColumnIndex, std::move(leftValues), std::move(rightValues), leftCount, rightCount});
  }

  // Depth tracking aligned to insertion path.
  std::vector<Tree::Id> openNodeStack;
  std::vector<std::size_t> depthStack;
  auto currentDepth = [&]() -> std::size_t {
    if (depthStack.empty()) return 0;
    return depthStack.back();
  };

  while (!tree.complete()) {
    if (maxDepth != 0 && currentDepth() >= maxDepth) {
      // Depth-limited leaf; treat as "no significant column" for now.
      // We still call findSignificantColumn() elsewhere to populate target counts; but at a
      // depth-limit leaf we want the target distribution of the rows that reached the node.
      // Rebuild enabled rows, run feature selection just to compute target counts.
      rebuildEnabledRowsForCurrentPosition();
      selector.findSignificantColumn();
      tree.createLeaf(LeafData::noSignificantColumn(selector.getTargetCounts()));
    } else {
      rebuildEnabledRowsForCurrentPosition();
      selector.findSignificantColumn();

      if (!selector.significantColumnFound() || !selector.significantPartitionFound()) {
        if (!selector.significantColumnFound()) {
          tree.createLeaf(LeafData::noSignificantColumn(selector.getTargetCounts()));
        } else {
          tree.createLeaf(LeafData::noSignificantPartition(selector.getSignificantColumnIndex(),
                                                          selector.getTargetCounts()));
        }
      } else {
        const auto nodeIdForCounts = static_cast<std::uint32_t>(tree.currentNodeID() < 0 ? 0 : tree.currentNodeID());
        const auto splitColumnIndex = static_cast<std::uint64_t>(selector.getSignificantColumnIndex());
        auto leftValues = selector.getFirstPartition();
        auto rightValues = selector.getSecondPartition();

        const auto countThreshold = nodeIdForCounts + 1;
        const auto leftCount =
          countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), leftValues);
        const auto rightCount =
          countEnabledRowsAfterApplyingPartition(countThreshold, static_cast<std::size_t>(splitColumnIndex), rightValues);

        tree.createNode(NodeData{splitColumnIndex,
                                std::move(leftValues),
                                std::move(rightValues),
                                leftCount,
                                rightCount});
      }
    }

    auto* cur = tree.getCurrentNode();
    if (!cur) break;

    if (openNodeStack.empty() || openNodeStack.back() != cur->id) {
      if (!cur->left && !cur->right) {
        const std::size_t d = depthStack.empty() ? 1 : (depthStack.back() + 1);
        openNodeStack.push_back(cur->id);
        depthStack.push_back(d);
      } else {
        while (!openNodeStack.empty() && openNodeStack.back() != cur->id) {
          openNodeStack.pop_back();
          depthStack.pop_back();
        }
      }
    }
  }

  return TreeBuilder{targetColumn,
                     maxDepth,
                     columnAlpha,
                     columnAlphaApplyBonferroni,
                     partitionAlpha,
                     partitionAlphaApplyBonferroni,
                     std::move(tree)};
}

} // namespace modelbuilder

#include <ModelBuilder/ModelBuilder.hpp>
#include <ModelBuilder/TreeBuilder.hpp>
#include <DataTable/DataTable.h>
#include <gtest/gtest.h>

#include <LeftTree/LeftTreeSerialization.hpp>

#include <filesystem>
#include <unordered_set>

TEST(ModelBuilder, BuildTree_Smoke) {
  modelbuilder::ModelBuilder mb;

  const std::filesystem::path dataDir = std::filesystem::path{MODELBUILDER_SOURCE_DIR} / "build" / "_deps" /
                                        "contingencytable-src" / "examples" / "datasets" / "titanic_output";

  mb.loadDataDir(dataDir.string());
  ASSERT_GT(mb.rowCount(), 0u);
  ASSERT_GT(mb.columnCount(), 0u);

  // Choose a small target (the dataset has multiple columns; we just want an index within bounds).
  mb.setTargetColumn(0);

  // Constrain analysis columns to a couple candidates if they exist.
  // (This also implicitly tests enabledColumns wiring.)
  if (mb.columnCount() >= 3) {
    mb.setAnalysisColumns({1, 2});
  }

  auto tree = mb.buildTree(/*maxDepth=*/2);
  EXPECT_GT(tree.elementCount(), 0u);
  ASSERT_NE(tree.root(), nullptr);

  // If the root element is a node and has payload, verify the new count fields are accessible.
  if (auto dataOpt = tree.getElementData(0); dataOpt.has_value()) {
    if (std::holds_alternative<modelbuilder::ModelBuilder::Tree::NodeDataResult>(*dataOpt)) {
      const auto& [elemType, nd] = std::get<modelbuilder::ModelBuilder::Tree::NodeDataResult>(*dataOpt);
      (void)elemType;
      if (nd.has_value()) {
        EXPECT_GE(nd->leftPartitionCount(), 0u);
        EXPECT_GE(nd->rightPartitionCount(), 0u);
      }
    }
  }
}

namespace {
std::uint64_t nodeTotalCount(const modelbuilder::NodeData& nd) {
  return nd.leftPartitionCount() + nd.rightPartitionCount();
}
} // namespace

TEST(ModelBuilder, BuildTree_ChildTotalsMatchParentBranchCount) {
  modelbuilder::ModelBuilder mb;

  // Use deterministic built-in dataset from the dependency.
  const std::filesystem::path dataDir = std::filesystem::path{MODELBUILDER_SOURCE_DIR} / "build" / "_deps" /
                                        "contingencytable-src" / "examples" / "datasets" / "titanic_output";

  mb.loadDataDir(dataDir.string());
  ASSERT_GT(mb.rowCount(), 0u);
  ASSERT_GT(mb.columnCount(), 2u);

  mb.setTargetColumn(1);
  // Enable a handful of analysis columns to ensure we get at least a couple internal nodes.
  mb.setAnalysisColumns({2});

  auto tree = mb.buildTree(/*maxDepth=*/3);
  ASSERT_NE(tree.root(), nullptr);

  // Walk all internal nodes and verify that if a child is also an internal node then:
  //   child.leftCount + child.rightCount == parent.<branch>Count
  // This is the invariant you described.
  //
  // IMPORTANT: Counts in ModelBuilder are defined as the number of enabled rows that reach each
  // branch (after applying the parent's partition filter), consistent with the row-marker scheme.
  for (std::size_t i = 0; i < tree.elementCount(); ++i) {
    const auto id = static_cast<modelbuilder::ModelBuilder::Tree::Id>(i);
    const auto* parent = tree.getNode(id);
    if (!parent || !parent->data.has_value()) continue;

    const auto& pnd = *parent->data;

    // Left branch
    if (parent->left && !parent->left->isLeaf()) {
      const auto* leftChild = tree.getNode(parent->left->id);
      ASSERT_NE(leftChild, nullptr);
      if (leftChild->data.has_value()) {
        const auto expected = pnd.leftPartitionCount();
        const auto actual = nodeTotalCount(*leftChild->data);
        EXPECT_EQ(actual, expected) << "parent=" << parent->id << " leftChild=" << leftChild->id;
      }
    }

    // Right branch
    if (parent->right && !parent->right->isLeaf()) {
      const auto* rightChild = tree.getNode(parent->right->id);
      ASSERT_NE(rightChild, nullptr);
      if (rightChild->data.has_value()) {
        const auto expected = pnd.rightPartitionCount();
        const auto actual = nodeTotalCount(*rightChild->data);
        EXPECT_EQ(actual, expected) << "parent=" << parent->id << " rightChild=" << rightChild->id;
      }
    }
  }
}

TEST(ModelBuilder, TreeSerialization_RoundTrip) {
  modelbuilder::ModelBuilder mb;

  const std::filesystem::path dataDir = std::filesystem::path{MODELBUILDER_SOURCE_DIR} / "build" / "_deps" /
                                        "contingencytable-src" / "examples" / "datasets" / "titanic_output";

  mb.loadDataDir(dataDir.string());
  mb.setTargetColumn(1);
  mb.setAnalysisColumns({2});

  auto tree = mb.buildTree(/*maxDepth=*/2);
  ASSERT_NE(tree.root(), nullptr);

  using Ser = lefttree::LeftTreeSerialization<modelbuilder::NodeData, modelbuilder::LeafData>;
  std::stringstream ss(std::ios::in | std::ios::out | std::ios::binary);
  Ser::serializeToStream(tree, ss);

  ss.seekg(0);
  auto tree2 = Ser::deserializeFromStream(ss);
  ASSERT_NE(tree2.root(), nullptr);
  EXPECT_EQ(tree2.elementCount(), tree.elementCount());

  // Spot-check root payload parity when both are nodes with payload.
  auto d0 = tree.getElementData(0);
  auto d1 = tree2.getElementData(0);
  ASSERT_TRUE(d0.has_value());
  ASSERT_TRUE(d1.has_value());
  ASSERT_TRUE(std::holds_alternative<modelbuilder::ModelBuilder::Tree::NodeDataResult>(*d0));
  ASSERT_TRUE(std::holds_alternative<modelbuilder::ModelBuilder::Tree::NodeDataResult>(*d1));

  const auto& [t0, n0] = std::get<modelbuilder::ModelBuilder::Tree::NodeDataResult>(*d0);
  const auto& [t1, n1] = std::get<modelbuilder::ModelBuilder::Tree::NodeDataResult>(*d1);
  (void)t0;
  (void)t1;
  ASSERT_TRUE(n0.has_value());
  ASSERT_TRUE(n1.has_value());
  EXPECT_EQ(n0->splitColumnIndex(), n1->splitColumnIndex());
  EXPECT_EQ(n0->leftPartitionCount(), n1->leftPartitionCount());
  EXPECT_EQ(n0->rightPartitionCount(), n1->rightPartitionCount());
  EXPECT_EQ(n0->leftPartitionValues(), n1->leftPartitionValues());
  EXPECT_EQ(n0->rightPartitionValues(), n1->rightPartitionValues());
}

TEST(TreeBuilder, ArtifactSerialization_RoundTrip) {
  // Use deterministic built-in dataset from a dependency.
  const std::filesystem::path dataDir = std::filesystem::path{MODELBUILDER_SOURCE_DIR} / "build" / "_deps" /
                                        "contingencytable-src" / "examples" / "datasets" / "titanic_output";

  const std::size_t targetColumn = 1;
  const std::size_t maxDepth = 2;
  const double columnAlpha = 0.05;
  const bool columnBonferroni = true;
  const double partitionAlpha = 0.01;
  const bool partitionBonferroni = false;

  // Build using a constrained analysis column set (build-time only).
  auto a1 = modelbuilder::TreeBuilder::buildFromDataDir(dataDir.string(),
                                                       targetColumn,
                                                       maxDepth,
                                                       columnAlpha,
                                                       columnBonferroni,
                                                       partitionAlpha,
                                                       partitionBonferroni,
                                                       /*analysisColumns=*/{2});
  ASSERT_NE(a1.tree().root(), nullptr);

  std::stringstream ss(std::ios::in | std::ios::out | std::ios::binary);
  a1.serialize(ss);

  ss.seekg(0);
  auto a2 = modelbuilder::TreeBuilder::deserialize(ss);
  ASSERT_NE(a2.tree().root(), nullptr);

  // Ensure the pinned params round-trip.
  EXPECT_EQ(a2.targetColumn(), a1.targetColumn());
  EXPECT_EQ(a2.maxDepth(), a1.maxDepth());
  EXPECT_DOUBLE_EQ(a2.columnAlpha(), a1.columnAlpha());
  EXPECT_EQ(a2.columnAlphaApplyBonferroni(), a1.columnAlphaApplyBonferroni());
  EXPECT_DOUBLE_EQ(a2.partitionAlpha(), a1.partitionAlpha());
  EXPECT_EQ(a2.partitionAlphaApplyBonferroni(), a1.partitionAlphaApplyBonferroni());

  // Tree blob round-trip sanity.
  EXPECT_EQ(a2.tree().elementCount(), a1.tree().elementCount());

  // Spot-check root payload parity.
  auto d0 = a1.tree().getElementData(0);
  auto d1 = a2.tree().getElementData(0);
  ASSERT_TRUE(d0.has_value());
  ASSERT_TRUE(d1.has_value());
  ASSERT_TRUE(std::holds_alternative<modelbuilder::TreeBuilder::Tree::NodeDataResult>(*d0));
  ASSERT_TRUE(std::holds_alternative<modelbuilder::TreeBuilder::Tree::NodeDataResult>(*d1));

  const auto& [t0, n0] = std::get<modelbuilder::TreeBuilder::Tree::NodeDataResult>(*d0);
  const auto& [t1, n1] = std::get<modelbuilder::TreeBuilder::Tree::NodeDataResult>(*d1);
  (void)t0;
  (void)t1;
  ASSERT_TRUE(n0.has_value());
  ASSERT_TRUE(n1.has_value());
  EXPECT_EQ(n0->splitColumnIndex(), n1->splitColumnIndex());
  EXPECT_EQ(n0->leftPartitionCount(), n1->leftPartitionCount());
  EXPECT_EQ(n0->rightPartitionCount(), n1->rightPartitionCount());
  EXPECT_EQ(n0->leftPartitionValues(), n1->leftPartitionValues());
  EXPECT_EQ(n0->rightPartitionValues(), n1->rightPartitionValues());
}

